127→type ViewMode = 'list' | 'grid' | 'form';
128→
129→interface SnippetFormState {
130→  name: string;
131→  keyword: string;
132→  snippet: string;
133→  category: string;
134→  isShared: boolean;
135→  expiresAt: string;
136→}
137→
138→const INITIAL_SNIPPET_FORM: SnippetFormState = {
139→  name: '',
140→  keyword: '',
141→  snippet: '',
142→  category: 'general',
143→  isShared: false,
144→  expiresAt: '',
145→};
146→
147→const SNIPPET_CATEGORIES = [
148→  {
149→    label: 'General',
150→    value: 'general',
151→  },
152→  {
153→    label: 'Code',
154→    value: 'code',
155→  },
156→  {
157→    label: 'Email',
158→    value: 'email',
159→  },
160→  {
161→    label: 'Template',
162→    value: 'template',
163→  },
164→];
