166→export function App() {
167→  const [query, setQuery] = useState('');
168→  const [selectedIndex, setSelectedIndex] = useState(0);
169→  const [actionsOpen, setActionsOpen] = useState(false);
170→  const [drilledItem, setDrilledItem] = useState<ListItemData | null>(null);
171→  const [viewMode, setViewMode] = useState<ViewMode>('list');
172→  const [snippetForm, setSnippetForm] =
173→    useState<SnippetFormState>(INITIAL_SNIPPET_FORM);
174→  const [formErrors, setFormErrors] = useState<
175→    Partial<Record<keyof SnippetFormState, string>>
176→  >({});
177→  const { toasts, show: showToast, hide: hideToast } = useToast();
178→
179→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
180→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
181→  const filteredColors = useMemo(
182→    () => filterColors(MOCK_COLORS, query),
183→    [query],
184→  );
185→  const selectedItem =
186→    viewMode === 'list' ? (drilledItem ?? allItems[selectedIndex]) : undefined;
187→
188→  const handleQueryChange = useCallback((value: string) => {
189→    setQuery(value);
190→    setSelectedIndex(0);
191→    setActionsOpen(false);
192→  }, []);
193→
194→  const handleActiveIndexChange = useCallback((index: number) => {
195→    setSelectedIndex(index);
196→    setActionsOpen(false);
197→  }, []);
198→
199→  const handleDrillIn = useCallback(() => {
200→    const item = allItems[selectedIndex];
201→    if (item) {
202→      if (item.id === 'color-picker') {
203→        setViewMode('grid');
204→        setQuery('');
205→        setSelectedIndex(0);
206→        setActionsOpen(false);
207→        showToast({
208→          style: 'success',
209→          title: 'Opened Color Picker',
210→        });
211→      } else {
212→        setDrilledItem(item);
213→        setQuery('');
214→        setActionsOpen(false);
215→        showToast({
216→          style: 'success',
217→          title: `Opened ${item.title}`,
218→        });
219→      }
220→    }
221→  }, [
222→    allItems,
223→    selectedIndex,
224→    showToast,
225→  ]);
226→
227→  const handleDrillBack = useCallback(() => {
228→    setDrilledItem(null);
229→    setViewMode('list');
230→    setQuery('');
231→    setSelectedIndex(0);
232→    setActionsOpen(false);
233→    setSnippetForm(INITIAL_SNIPPET_FORM);
234→    setFormErrors({});
235→  }, []);
236→
237→  const handleOpenCreateSnippet = useCallback(() => {
238→    setViewMode('form');
239→    setQuery('');
240→    setSelectedIndex(0);
241→    setActionsOpen(false);
242→    setSnippetForm(INITIAL_SNIPPET_FORM);
243→    setFormErrors({});
244→  }, []);
245→
246→  const handleSubmitSnippet = useCallback(() => {
247→    const errors: Partial<Record<keyof SnippetFormState, string>> = {};
248→    if (!snippetForm.name.trim()) {
249→      errors.name = 'Name is required';
250→    }
251→    if (!snippetForm.snippet.trim()) {
252→      errors.snippet = 'Snippet content is required';
253→    }
254→    setFormErrors(errors);
255→    if (Object.keys(errors).length > 0) {
256→      return;
257→    }
258→    showToast({
259→      style: 'success',
260→      title: 'Snippet Created',
261→      message: snippetForm.name,
262→    });
263→    handleDrillBack();
264→  }, [
265→    snippetForm,
266→    showToast,
267→    handleDrillBack,
268→  ]);
269→
270→  const handleGridAction = useCallback(
271→    (index: number) => {
272→      const color = filteredColors[index];
273→      if (color) {
274→        showToast({
275→          style: 'info',
276→          title: 'Copied color',
277→          message: color.color,
278→        });
279→      }
280→    },
281→    [
282→      filteredColors,
283→      showToast,
284→    ],
285→  );
286→
287→  const breadcrumbs: BreadcrumbItem[] | undefined =
288→    viewMode === 'form'
289→      ? [
290→          {
291→            label: 'Raycast',
292→            onBack: handleDrillBack,
293→          },
294→          { label: 'Create Snippet' },
295→        ]
296→      : viewMode === 'grid'
297→        ? [
298→            {
299→              label: 'Raycast',
300→              onBack: handleDrillBack,
301→            },
302→            { label: 'Color Picker' },
303→          ]
304→        : drilledItem
305→          ? [
306→              {
307→                label: 'Raycast',
308→                onBack: handleDrillBack,
309→              },
310→              { label: drilledItem.title },
311→            ]
312→          : undefined;
313→
314→  const toggleActions = useCallback(() => {
315→    setActionsOpen(prev => !prev);
316→  }, []);
317→
318→  const closeActions = useCallback(() => {
319→    setActionsOpen(false);
320→  }, []);
321→
322→  useEffect(() => {
