340→    window.addEventListener('keydown', handleKeyDown);
341→    return () => window.removeEventListener('keydown', handleKeyDown);
342→  }, [
343→    viewMode,
344→    handleSubmitSnippet,
345→    handleOpenCreateSnippet,
346→  ]);
347→
348→  const detail = selectedItem?.detail;
349→
350→  const dropdownActions = useMemo(
351→    () => [
352→      {
353→        label: 'Open',
354→        shortcut: <Kbd keys={['↵']} />,
355→        onClick: () => {
356→          if (selectedItem) {
357→            showToast({
358→              style: 'success',
359→              title: `Opened ${selectedItem.title}`,
360→            });
361→          }
362→        },
363→      },
364→      {
365→        label: 'Copy Name',
366→        shortcut: (
367→          <Kbd
368→            keys={[
369→              '⌘',
370→              'C',
371→            ]}
372→          />
373→        ),
374→        onClick: () => {
375→          if (selectedItem) {
376→            showToast({
377→              style: 'info',
378→              title: 'Copied to clipboard',
379→              message: selectedItem.title,
380→            });
381→          }
382→        },
383→      },
384→      {
385→        label: 'Show Detail',
386→        shortcut: (
387→          <Kbd
388→            keys={[
389→              '⌘',
390→              'D',
391→            ]}
392→          />
393→        ),
394→        onClick: () => {
395→          showToast({
396→            style: 'info',
397→            title: 'Detail panel toggled',
398→          });
399→        },
400→      },
401→      {
402→        label: 'Create Snippet',
403→        shortcut: (
404→          <Kbd
405→            keys={[
406→              '⌘',
407→              'N',
408→            ]}
409→          />
410→        ),
411→        onClick: handleOpenCreateSnippet,
412→      },
413→      {
414→        label: 'Delete',
415→        shortcut: (
416→          <Kbd
417→            keys={[
418→              '⌘',
419→              '⌫',
420→            ]}
421→          />
422→        ),
423→        onClick: () => {
424→          showToast({
425→            style: 'error',
426→            title: 'Cannot delete',
427→            message: 'This item is read-only',
428→          });
429→        },
430→      },
431→    ],
432→    [
433→      selectedItem,
434→      showToast,
435→      handleOpenCreateSnippet,
436→    ],
437→  );
438→
439→  const activeDescendantId =
440→    viewMode === 'grid'
441→      ? filteredColors.length > 0
442→        ? `grid-item-${selectedIndex}`
443→        : undefined
444→      : allItems.length > 0
445→        ? `list-item-${selectedIndex}`
446→        : undefined;
447→
448→  return (
449→    <CommandPalette isLoading>
450→      <SearchBar
451→        value={query}
452→        onChange={handleQueryChange}
453→        activeDescendantId={activeDescendantId}
454→        breadcrumbs={breadcrumbs}
455→      />
456→      <div
457→        className={`command-palette__body${detail ? ' command-palette__body--has-detail' : ''}`}
458→      >
459→        <div className="command-palette__list-container">
460→          {viewMode === 'form' ? (
