462→              <FormTextField
463→                label="Name"
464→                value={snippetForm.name}
465→                onChange={v =>
466→                  setSnippetForm(prev => ({
467→                    ...prev,
468→                    name: v,
469→                  }))
470→                }
471→                placeholder="e.g. Email Signature"
472→                error={formErrors.name}
473→                autoFocus
474→              />
475→              <FormTextField
476→                label="Keyword"
477→                value={snippetForm.keyword}
478→                onChange={v =>
479→                  setSnippetForm(prev => ({
480→                    ...prev,
481→                    keyword: v,
482→                  }))
483→                }
484→                placeholder="e.g. !sig"
485→                description="Type this to expand the snippet"
486→              />
487→              <FormDropdown
488→                label="Category"
489→                value={snippetForm.category}
490→                onChange={v =>
491→                  setSnippetForm(prev => ({
492→                    ...prev,
493→                    category: v,
494→                  }))
495→                }
496→                options={SNIPPET_CATEGORIES}
497→                placeholder="Select a category"
498→              />
499→              <FormTextArea
500→                label="Snippet"
501→                value={snippetForm.snippet}
502→                onChange={v =>
503→                  setSnippetForm(prev => ({
504→                    ...prev,
505→                    snippet: v,
506→                  }))
507→                }
508→                placeholder="Enter your snippet content..."
509→                error={formErrors.snippet}
510→                rows={5}
511→              />
512→              <FormCheckbox
513→                label="Share with team"
514→                checked={snippetForm.isShared}
515→                onChange={v =>
516→                  setSnippetForm(prev => ({
517→                    ...prev,
518→                    isShared: v,
519→                  }))
520→                }
521→                description="Make this snippet available to your team members"
522→              />
523→              <FormDatePicker
524→                label="Expires"
525→                value={snippetForm.expiresAt}
526→                onChange={v =>
527→                  setSnippetForm(prev => ({
528→                    ...prev,
529→                    expiresAt: v,
530→                  }))
531→                }
532→                description="Optional expiration date"
533→              />
534→            </Form>
535→          ) : viewMode === 'grid' ? (
536→            filteredColors.length === 0 ? (
537→              <EmptyState
538→                icon={<SearchIcon />}
539→                title="No Colors"
540→                description="Try a different search term"
541→              />
542→            ) : (
543→              <Grid
544→                itemCount={filteredColors.length}
545→                columns={4}
546→                onActiveIndexChange={handleActiveIndexChange}
547→                onAction={handleGridAction}
548→              >
549→                {filteredColors.map((color, index) => (
550→                  <GridItem
551→                    key={color.id}
552→                    index={index}
553→                    icon={<ColorSwatch color={color.color} />}
554→                    title={color.title}
555→                    subtitle={color.subtitle}
556→                  />
557→                ))}
558→              </Grid>
559→            )
560→          ) : allItems.length === 0 ? (
561→            <EmptyState
562→              icon={<SearchIcon />}
563→              title="No Results"
564→              description="Try a different search term"
565→            />
566→          ) : (
567→            <List
568→              itemCount={allItems.length}
569→              onActiveIndexChange={handleActiveIndexChange}
570→              onAction={handleDrillIn}
571→            >
572→              {(() => {
573→                let globalIndex = 0;
574→                return filtered.map(section => (
575→                  <ListSection key={section.title} title={section.title}>
576→                    {section.items.map(item => {
577→                      const idx = globalIndex++;
578→                      return (
579→                        <ListItem
580→                          key={item.id}
581→                          index={idx}
582→                          title={item.title}
583→                          subtitle={item.subtitle}
584→                          icon={item.icon}
585→                          accessories={item.accessories}
586→                        />
587→                      );
588→                    })}
589→                  </ListSection>
590→                ));
591→              })()}
592→            </List>
593→          )}
594→        </div>
595→        {detail && (
596→          <Detail
597→            markdown={detail.markdown}
598→            metadata={
599→              detail.metadata ? (
600→                <DetailMetadata>
601→                  {detail.metadata.map(renderMetadataEntry)}
602→                </DetailMetadata>
603→              ) : undefined
604→            }
605→          />
606→        )}
607→      </div>
608→      <ActionPanel
609→        actions={
610→          viewMode === 'form'
611→            ? [
612→                {
613→                  label: 'Submit',
614→                  shortcut: (
615→                    <Kbd
616→                      keys={[
617→                        '⌘',
618→                        '↵',
619→                      ]}
620→                    />
621→                  ),
622→                  onClick: handleSubmitSnippet,
623→                },
624→              ]
625→            : [
626→                {
627→                  label: 'Open',
628→                  shortcut: <Kbd keys={['↵']} />,
629→                },
630→                {
631→                  label: 'Actions',
632→                  shortcut: (
633→                    <Kbd
634→                      keys={[
635→                        '⌘',
636→                        'K',
637→                      ]}
638→                    />
639→                  ),
640→                  onClick: toggleActions,
641→                },
642→              ]
643→        }
644→        dropdownOpen={actionsOpen}
645→        dropdownActions={dropdownActions}
646→        onDropdownClose={closeActions}
647→      />
648→      <ToastContainer toasts={toasts} onDismiss={hideToast} />
649→    </CommandPalette>
650→  );
651→}
