 1→import { useCallback, useEffect, useRef, useState } from 'react';
 2→import type { ToastData, ToastStyle } from '../components/toast/toast';
 3→
 4→const AUTO_DISMISS_MS = 3000;
 5→const EXIT_ANIMATION_MS = 200;
 6→
 7→let nextId = 0;
 8→
 9→interface ShowToastOptions {
10→  style?: ToastStyle;
11→  title: string;
12→  message?: string;
13→}
14→
15→export function useToast() {
16→  const [toasts, setToasts] = useState<ToastData[]>([]);
17→  const timersRef = useRef<Map<string, ReturnType<typeof setTimeout>>>(
18→    new Map(),
19→  );
20→
21→  useEffect(() => {
22→    const timers = timersRef.current;
23→    return () => {
24→      timers.forEach(timer => clearTimeout(timer));
25→      timers.clear();
26→    };
27→  }, []);
28→
29→  const hide = useCallback((id: string) => {
30→    const timer = timersRef.current.get(id);
31→    if (timer) {
32→      clearTimeout(timer);
33→      timersRef.current.delete(id);
34→    }
35→    setToasts(prev =>
36→      prev.map(t =>
37→        t.id === id
38→          ? {
39→              ...t,
40→              exiting: true,
41→            }
42→          : t));
43→    const exitTimer = setTimeout(() => {
44→      timersRef.current.delete(`${id}-exit`);
45→      setToasts(prev => prev.filter(t => t.id !== id));
46→    }, EXIT_ANIMATION_MS);
47→    timersRef.current.set(`${id}-exit`, exitTimer);
48→  }, []);
49→
50→  const show = useCallback(
51→    (options: ShowToastOptions) => {
52→      const id = String(nextId++);
53→      const toast: ToastData = {
54→        id,
55→        style: options.style ?? 'info',
56→        title: options.title,
57→        message: options.message,
58→        exiting: false,
59→      };
60→
61→      setToasts(prev => [
62→        toast,
63→        ...prev,
64→      ]);
65→
66→      const timer = setTimeout(() => {
67→        timersRef.current.delete(id);
68→        hide(id);
69→      }, AUTO_DISMISS_MS);
70→      timersRef.current.set(id, timer);
71→
72→      return id;
73→    },
74→    [hide],
75→  );
76→
77→  return {
78→    toasts,
79→    show,
80→    hide,
81→  };
82→}
