  1→import {
  2→  type ReactNode,
  3→  useCallback,
  4→  useEffect,
  5→  useMemo,
  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→import './grid.scss';
 10→import { GridContext } from './grid_context';
 11→
 12→interface GridProps {
 13→  children: ReactNode;
 14→  itemCount: number;
 15→  columns?: 3 | 4 | 5 | 6;
 16→  onActiveIndexChange?: (index: number) => void;
 17→  onAction?: (index: number) => void;
 18→}
 19→
 20→export function Grid({
 21→  children,
 22→  itemCount,
 23→  columns = 4,
 24→  onActiveIndexChange,
 25→  onAction,
 26→}: GridProps) {
 27→  const [activeIndex, setActiveIndexRaw] = useState(0);
 28→  const containerRef = useRef<HTMLDivElement>(null);
 29→
 30→  const setActiveIndex = useCallback(
 31→    (index: number) => {
 32→      setActiveIndexRaw(index);
 33→      onActiveIndexChange?.(index);
 34→    },
 35→    [onActiveIndexChange],
 36→  );
 37→
 38→  useEffect(() => {
 39→    if (itemCount === 0) {
 40→      setActiveIndex(0);
 41→    } else if (activeIndex >= itemCount) {
 42→      setActiveIndex(itemCount - 1);
 43→    }
 44→  }, [
 45→    itemCount,
 46→    activeIndex,
 47→    setActiveIndex,
 48→  ]);
 49→
 50→  useEffect(() => {
 51→    const container = containerRef.current;
 52→    if (!container) return;
 53→
 54→    const activeElement = container.querySelector<HTMLElement>(
 55→      `[data-grid-index="${activeIndex}"]`,
 56→    );
 57→    activeElement?.scrollIntoView({ block: 'nearest' });
 58→  }, [activeIndex]);
 59→
 60→  useEffect(() => {
 61→    function handleKeyDown(e: KeyboardEvent) {
 62→      if (itemCount === 0) return;
 63→      if (e.metaKey || e.ctrlKey || e.altKey) return;
 64→
 65→      const isTextInput =
 66→        e.target instanceof HTMLInputElement ||
 67→        e.target instanceof HTMLTextAreaElement;
 68→
 69→      const row = Math.floor(activeIndex / columns);
 70→      const col = activeIndex % columns;
 71→      const totalRows = Math.ceil(itemCount / columns);
 72→
 73→      switch (e.key) {
 74→        case 'ArrowRight': {
 75→          if (isTextInput) return;
 76→          e.preventDefault();
 77→          const next = activeIndex + 1;
 78→          setActiveIndex(next < itemCount ? next : 0);
 79→          break;
 80→        }
 81→        case 'ArrowLeft': {
 82→          if (isTextInput) return;
 83→          e.preventDefault();
 84→          const prev = activeIndex - 1;
 85→          setActiveIndex(prev >= 0 ? prev : itemCount - 1);
 86→          break;
 87→        }
 88→        case 'ArrowDown': {
 89→          e.preventDefault();
 90→          const nextRow = row + 1;
 91→          if (nextRow < totalRows) {
 92→            const nextIndex = nextRow * columns + col;
 93→            setActiveIndex(nextIndex < itemCount ? nextIndex : itemCount - 1);
 94→          } else {
 95→            setActiveIndex(col < itemCount ? col : 0);
 96→          }
 97→          break;
 98→        }
 99→        case 'ArrowUp': {
100→          e.preventDefault();
101→          const prevRow = row - 1;
102→          if (prevRow >= 0) {
103→            setActiveIndex(prevRow * columns + col);
104→          } else {
105→            const lastRowIndex = (totalRows - 1) * columns + col;
106→            setActiveIndex(
107→              lastRowIndex < itemCount ? lastRowIndex : itemCount - 1,
108→            );
109→          }
110→          break;
111→        }
112→        case 'Enter': {
113→          e.preventDefault();
114→          onAction?.(activeIndex);
115→          break;
116→        }
117→      }
118→    }
119→
120→    window.addEventListener('keydown', handleKeyDown);
121→    return () => window.removeEventListener('keydown', handleKeyDown);
122→  }, [
123→    activeIndex,
124→    itemCount,
125→    columns,
126→    setActiveIndex,
127→    onAction,
128→  ]);
129→
130→  const contextValue = useMemo(
131→    () => ({
132→      activeIndex,
133→      setActiveIndex,
134→      columns,
135→    }),
136→    [
137→      activeIndex,
138→      setActiveIndex,
139→      columns,
140→    ],
141→  );
142→
143→  return (
144→    <GridContext value={contextValue}>
145→      <div
146→        ref={containerRef}
147→        className="grid"
148→        role="listbox"
149→        id="command-grid"
150→        style={{ '--grid-columns': columns } as React.CSSProperties}
151→      >
152→        {children}
153→      </div>
154→    </GridContext>
155→  );
156→}
