 9→export function Form({ children, onSubmit }: FormProps) {
10→  function handleSubmit(e: FormEvent) {
11→    e.preventDefault();
12→  }
13→
14→  function handleKeyDown(e: React.KeyboardEvent) {
15→    if (e.key === 'Enter' && e.metaKey && onSubmit) {
16→      e.preventDefault();
17→      onSubmit();
18→    }
19→  }
20→
21→  return (
22→    <form
23→      className="form"
24→      onSubmit={handleSubmit}
25→      onKeyDown={handleKeyDown}
26→      noValidate
27→    >
